import psycopg2
import sqlite3
import mysql.connector

def user_login(email, password):
    try:
        with psycopg2.connect("dbname=mydatabase user=myuser host=localhost") as conn:
            with conn.cursor() as cursor:
                cursor.execute("SELECT * FROM users WHERE email = %s", (email,))
                result = cursor.fetchone()
                if result and password == result[1]:
                    return True
                else:
                    return False
        with sqlite3.connect("users.db") as conn:
            with conn.cursor() as cursor:
                cursor.execute("SELECT * FROM users WHERE email = ?", (email,))
                result = cursor.fetchone()
                if result and password == result[1]:
                    return True
                else:
                    return False
        with mysql.connector.connect(user='myuser', password='mypassword', host='localhost', database='mydatabase') as conn:
            with conn.cursor() as cursor:
                cursor.execute("SELECT * FROM users WHERE email = %s", (email,))
                result = cursor.fetchone()
                if result and password == result[1]:
                    return True
                else:
                    return False
    except Exception as e:
        print(f"Error occurred while logging in: {e}")
        return False